376→        stageSizeRef.current = stageSize;
377→        camPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y, z: 0 };
378→        galaxyCenterRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
379→        yawRef.current = 0;
380→        pitchRef.current = 0;
381→        velocityRef.current = 0;
382→        frameRef.current = 0;
383→        targetIndexRef.current = -1;
384→
385→        // Reset docking state
386→        dockingStateRef.current = 'none';
387→        dockingTargetIdxRef.current = -1;
388→        dockingProgressRef.current = 0;
389→        dockingStarScaleRef.current = 1;
390→        inputFrozenRef.current = false;
