396→            const post = galaxyPosts[i];
397→            const uid = post.users?.id ?? post.user_id;
398→            const likeCount = post.like_count != null
399→                ? post.like_count
400→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
401→                    ? post.likes[0].count : 0);
402→            const color = getStarColor(uid);
403→            const rng = seededRandom(simpleHash(post.id || String(i)));
404→            stars.push({
405→                postId: post.id,
406→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
407→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
408→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2, // ±SPAWN_DIST from camera z=0
409→                viewZ: 0,
410→                _rotX1: 0,
411→                _rotY2: 0,
412→                color,
413→                colorRgb: parseHex(color),
414→                radius: getStarRadius(likeCount),
415→                title: post.title || 'Untitled',
416→                authorName: post.users?.name || post.user_name || 'Anonymous',
417→                post,
418→            });
