456→
457→        // Start rAF
458→        rafRef.current = requestAnimationFrame(tick);
459→    }, [tick]);
460→
461→    const exit = useCallback(() => {
462→        isActiveRef.current = false;
463→        if (rafRef.current) {
464→            cancelAnimationFrame(rafRef.current);
465→            rafRef.current = null;
466→        }
467→        // Remove key listeners
468→        if (onKeyDownRef.current) {
469→            window.removeEventListener('keydown', onKeyDownRef.current);
470→            window.removeEventListener('keyup', onKeyUpRef.current);
