474→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
475→        // Reset docking
476→        dockingStateRef.current = 'none';
477→        dockingTargetIdxRef.current = -1;
478→        dockingProgressRef.current = 0;
479→        dockingStarScaleRef.current = 1;
480→        inputFrozenRef.current = false;
481→        dockingCallbackRef.current = null;
482→    }, []);
483→
484→    const project = useCallback((star, cx, cy) => {
485→        if (star.viewZ <= MIN_VIEW_Z) return null; // behind camera
486→
487→        const stageWidth = stageSizeRef.current.width;
488→        const focalLength = stageWidth * 0.6; // ~80° FOV
489→        const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
490→        const projY = cy - (star._rotY2 / star.viewZ) * focalLength; // negate Y for screen coords
491→        const scale = focalLength / star.viewZ;
492→
493→        return { projX, projY, scale };
494→    }, []);
