496→    const getTargetedPost = useCallback(() => {
497→        const idx = targetIndexRef.current;
498→        if (idx < 0 || idx >= starsRef.current.length) return null;
499→        return starsRef.current[idx].post;
500→    }, []);
501→
502→    const getSpeedRatio = useCallback(() => {
503→        return velocityRef.current / MAX_SPEED;
504→    }, []);
505→
506→    const getDockingState = useCallback(() => {
507→        return dockingStateRef.current;
508→    }, []);
509→
510→    const getSessionSnapshot = useCallback(() => {
511→        const cam = camPosRef.current;
512→        const gc = galaxyCenterRef.current;
513→        // Back up camera along reverse forward vector so restore doesn't land inside the star
514→        const RESTORE_BACK_OFFSET = 60;
515→        const fwd = getForwardVector(yawRef.current, pitchRef.current);
516→        return {
517→            camX: cam.x - fwd.x * RESTORE_BACK_OFFSET,
518→            camY: cam.y - fwd.y * RESTORE_BACK_OFFSET,
519→            camZ: cam.z - fwd.z * RESTORE_BACK_OFFSET,
520→            yaw: yawRef.current,
521→            pitch: pitchRef.current,
522→            velocity: 0,
523→            galaxyCenterX: gc.x,
524→            galaxyCenterY: gc.y,
525→            timestamp: Date.now(),
526→        };
527→    }, []);
528→
529→    const restoreFromSnapshot = useCallback((snapshot, galaxyPosts, stageSize) => {
530→        // Clean up any existing loop/listeners before restoring
531→        isActiveRef.current = false;
532→        if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
533→        if (onKeyDownRef.current) {
534→            window.removeEventListener('keydown', onKeyDownRef.current);
535→            window.removeEventListener('keyup', onKeyUpRef.current);
