537→        }
538→
539→        stageSizeRef.current = stageSize;
540→        camPosRef.current = { x: snapshot.camX, y: snapshot.camY, z: snapshot.camZ };
541→        yawRef.current = snapshot.yaw;
542→        pitchRef.current = snapshot.pitch;
543→        velocityRef.current = 0; // smooth re-entry
544→        frameRef.current = 0;
545→        targetIndexRef.current = -1;
546→
547→        // Reset docking state
548→        dockingStateRef.current = 'none';
549→        dockingTargetIdxRef.current = -1;
550→        dockingProgressRef.current = 0;
551→        dockingStarScaleRef.current = 1;
552→        inputFrozenRef.current = false;
553→        // Suppress auto-dock for 2s after restore to prevent redirect loop
554→        dockCooldownRef.current = performance.now() + 2000;
555→
556→        // Build star array — use stored galaxy center for consistent star placement
557→        const galaxyCenter = snapshot.galaxyCenterX != null
558→            ? { x: snapshot.galaxyCenterX, y: snapshot.galaxyCenterY }
559→            : { x: snapshot.camX, y: snapshot.camY };
560→        galaxyCenterRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
561→        const stars = [];
562→        for (let i = 0; i < galaxyPosts.length; i++) {
563→            const post = galaxyPosts[i];
564→            const uid = post.users?.id ?? post.user_id;
565→            const likeCount = post.like_count != null
566→                ? post.like_count
567→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
568→                    ? post.likes[0].count : 0);
569→            const color = getStarColor(uid);
570→            const rng = seededRandom(simpleHash(post.id || String(i)));
571→            stars.push({
572→                postId: post.id,
573→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
574→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
575→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2,
576→                viewZ: 0,
577→                _rotX1: 0,
578→                _rotY2: 0,
579→                color,
580→                colorRgb: parseHex(color),
581→                radius: getStarRadius(likeCount),
582→                title: post.title || 'Untitled',
583→                authorName: post.users?.name || post.user_name || 'Anonymous',
584→                post,
585→            });
586→        }
587→
588→        starsRef.current = stars;
589→
590→        const indices = new Array(stars.length);
591→        for (let i = 0; i < stars.length; i++) indices[i] = i;
592→        sortedIndicesRef.current = indices;
593→
594→        // Key listeners
595→        const onKeyDown = (e) => {
596→            const key = e.key.toLowerCase();
597→            if (key === 'w') keysRef.current.w = true;
598→            if (key === 's') keysRef.current.s = true;
599→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
600→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
601→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
602→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
603→        };
604→        const onKeyUp = (e) => {
605→            const key = e.key.toLowerCase();
606→            if (key === 'w') keysRef.current.w = false;
607→            if (key === 's') keysRef.current.s = false;
608→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
609→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
610→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
611→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
612→        };
613→
614→        onKeyDownRef.current = onKeyDown;
615→        onKeyUpRef.current = onKeyUp;
616→        window.addEventListener('keydown', onKeyDown);
617→        window.addEventListener('keyup', onKeyUp);
618→
619→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
620→        isActiveRef.current = true;
621→
622→        rafRef.current = requestAnimationFrame(tick);
623→    }, [tick]);
624→
625→    const setDockingCallback = useCallback((cb) => {
626→        // Don't overwrite a callback that's already mid-animation
627→        const state = dockingStateRef.current;
628→        if (state === 'none' || state === 'magnet') {
629→            dockingCallbackRef.current = cb;
630→        }
631→        // Always store as persistent auto-dock callback
632→        autoDockCbRef.current = cb;
633→    }, []);
634→
635→    const abortDocking = useCallback(() => {
636→        if (dockingStateRef.current === 'magnet') {
637→            dockingStateRef.current = 'none';
638→            dockingTargetIdxRef.current = -1;
639→            dockingProgressRef.current = 0;
640→            dockingStarScaleRef.current = 1;
641→        }
642→        // Approaching/flash are non-interruptible
643→    }, []);
644→
645→    const triggerDocking = useCallback((targetIdx, callback) => {
646→        if (dockingStateRef.current !== 'none' && dockingStateRef.current !== 'magnet') return;
647→        dockingStateRef.current = 'approaching';
648→        dockingTargetIdxRef.current = targetIdx;
649→        dockingStartTimeRef.current = performance.now();
650→        dockingProgressRef.current = 0;
651→        dockingStarScaleRef.current = 1;
652→        inputFrozenRef.current = true;
653→        if (callback) dockingCallbackRef.current = callback;
654→    }, []);
655→
656→    return {
657→        enter,
658→        exit,
659→        layerRef,
660→        starsRef,
661→        sortedIndicesRef,
662→        rocketPos: camPosRef,
663→        heading: yawRef,
664→        pitch: pitchRef,
665→        velocity: velocityRef,
666→        targetIndexRef,
667→        stageSizeRef,
668→        project,
669→        isActive: isActiveRef,
670→        getTargetedPost,
671→        getSpeedRatio,
672→        // Docking API
673→        getDockingState,
674→        getSessionSnapshot,
675→        restoreFromSnapshot,
676→        setDockingCallback,
677→        abortDocking,
678→        triggerDocking,
679→        dockingStateRef,
680→        dockingTargetIdxRef,
681→        dockingProgressRef,
682→        dockingStarScaleRef,
683→        inputFrozenRef,
684→    };
685→};
