  95→    }, [focusedConstellation]);
  96→
  97→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
  98→    const showTitles = zoom > 0.5;
  99→
 100→    // Sector partitioning for scalable local gravity math.
 101→    const postSectorIndex = useMemo(() => (
 102→        buildSectorIndex(
 103→            postArray,
 104→            (post) => ({
 105→                x: post?.display_x ?? post?.universe_x,
 106→                y: post?.display_y ?? post?.universe_y,
