 122→    const activePosts = useMemo(() => {
 123→        if (activeSectorKeys.size === 0) return postArray;
 124→
 125→        const next = [];
 126→        for (const key of activeSectorKeys) {
 127→            const bucket = postSectorIndex.get(key);
 128→            if (bucket?.length) next.push(...bucket);
 129→        }
 130→        return next;
 131→    }, [postArray, postSectorIndex, activeSectorKeys]);
