 141→    const { centroidByUser } = useMemo(
 142→        () => computeGalaxyCentroids(postArray),
 143→        [postArray]
 144→    );
 145→
 146→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
 147→    const hashGalaxies = useMemo(() => {
 148→        const seen = new Map();
 149→        for (const post of postArray) {
 150→            const uid = post.users?.id ?? post.user_id;
 151→            if (!uid || seen.has(uid)) continue;
 152→            const hash = userHomeCoords(uid);
 153→            seen.set(uid, {
 154→                userId: uid,
 155→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
 156→                x: hash.x,
 157→                y: hash.y,
 158→            });
 159→        }
 160→        return Array.from(seen.values());
 161→    }, [postArray]);
