 163→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
 164→    const centroidTargets = useMemo(() => {
 165→        const map = new Map();
 166→        for (const c of centroids) {
 167→            if (c.galaxy_x != null && c.galaxy_y != null) {
 168→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
 169→            }
 170→        }
 171→        return map;
 172→    }, [centroids]);
 173→
 174→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
 175→    const {
 176→        galaxyPositions,
 177→        starPullOffsets,
 178→        isSettled,
 179→        galaxyEdges: effectiveGalaxyEdges,
 180→        hasEmbeddingGravity,
 181→    } = useCosmicGravity({
 182→        galaxies: hashGalaxies,
 183→        centroidTargets,
 184→        edges: galaxyEdges,
 185→        posts: postArray,
 186→        starPulls,
 187→        centroidByUser,
 188→        activeSectorKeys,
 189→        activePostIds,
 190→        sectorSize: SECTOR_SIZE,
 191→    });
 192→
 193→    // ── Render galaxies = hash galaxies with animated positions ──────
 194→    const galaxies = useMemo(() => {
 195→        return hashGalaxies.map(g => {
 196→            const animated = galaxyPositions.get(g.userId);
 197→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
 198→        });
 199→    }, [hashGalaxies, galaxyPositions]);
 200→
 201→    // Home position for distance tracker — same resolution as auto-focus.
 202→    const homePosition = useMemo(() => {
 203→        if (!userId) return { x: 0, y: 0 };
 204→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
 205→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
 206→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
 207→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
 208→
 209→    const getComputedStarPosition = useCallback((post) => {
 210→        if (!post) return null;
 211→
 212→        const uid = post.users?.id ?? post.user_id;
 213→        const hashGal = userHomeCoords(uid);
 214→        const animGal = galaxyPositions.get(uid);
 215→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 216→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 217→        const pull = starPullOffsets.get(post.id);
 218→
 219→        const baseX = post.universe_x ?? post.display_x;
 220→        const baseY = post.universe_y ?? post.display_y;
 221→        if (baseX == null || baseY == null) return null;
 222→
 223→        return {
 224→            x: baseX + galDx + (pull?.dx ?? 0),
 225→            y: baseY + galDy + (pull?.dy ?? 0),
 226→        };
 227→    }, [galaxyPositions, starPullOffsets]);
 228→
 229→    // ── Hoisted computedStarPositions for sharing across layers ──────
 230→    const computedStarPositions = useMemo(() => {
 231→        const map = new Map();
 232→        for (const post of postArray) {
 233→            const uid = post.users?.id ?? post.user_id;
 234→            const hashGal = userHomeCoords(uid);
 235→            const animGal = galaxyPositions.get(uid);
 236→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 237→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 238→            const pull = starPullOffsets.get(post.id);
 239→
 240→            const baseX = post.universe_x ?? post.display_x;
 241→            const baseY = post.universe_y ?? post.display_y;
 242→            if (baseX == null || baseY == null) continue;
 243→
 244→            let x = baseX + galDx + (pull?.dx ?? 0);
 245→            let y = baseY + galDy + (pull?.dy ?? 0);
 246→
 247→            map.set(post.id, { x, y });
 248→        }
 249→        return map;
 250→    }, [postArray, galaxyPositions, starPullOffsets]);
 251→
 252→    // ── Constellation pull offsets (spring constraint) ─────────────
 253→    const acceptedConstellations = useMemo(
 254→        () => constellations.filter(c => c.status === 'accepted'),
 255→        [constellations]
 256→    );
 257→
 258→    const constellationPullOffsets = useMemo(
 259→        () => computeConstellationPullOffsets(acceptedConstellations, computedStarPositions),
