 263→    // ── Final star positions with constellation pull applied ───────
 264→    const finalStarPositions = useMemo(() => {
 265→        if (constellationPullOffsets.size === 0) return computedStarPositions;
 266→
 267→        const map = new Map(computedStarPositions);
 268→        for (const [postId, offset] of constellationPullOffsets) {
 269→            const pos = map.get(postId);
 270→            if (pos) {
 271→                map.set(postId, {
 272→                    x: pos.x + offset.dx,
 273→                    y: pos.y + offset.dy,
